package be.schaubroeck.lpb.rkm.rekenmotor.util;

import be.schaubroeck.lpb.rkm.rekenmotor.Take;
import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.NlpPrestatie;
import be.schaubroeck.lpb.tools.Vergoeding;
import be.schaubroeck.lpb.tools.caching.ake.AardKodeExtensieFacade;
import be.schaubroeck.lpb.tools.enumtypes.Regulkode;
import lombok.extern.slf4j.Slf4j;

@Slf4j
public class LoonCodeManagerImp implements LoonCodeManager {

    public static final String STREEP = " - ";
    private final RegulManager regulManager;
    private final AardKodeExtensieFacade aardKodeExtensieFacade;

    public LoonCodeManagerImp(RegulManager regulManager, AardKodeExtensieFacade aardKodeExtensieFacade) {
        this.regulManager = regulManager;
        this.aardKodeExtensieFacade = aardKodeExtensieFacade;
    }

    @Override
    public AardKodeExtensie getByTake(Integer tijdperk, Integer aard, Integer code, Integer extensie) {
        AardKodeExtensie aardKodeExtensie = aardKodeExtensieFacade.getAkeByTijdperkAardCodeExtensie(tijdperk, aard, code, extensie);
        checkAardKodeExtensie(aardKodeExtensie, "getAkeByTijdperkAardCodeExtensie " + tijdperk + STREEP + aard + STREEP + code + STREEP + extensie);
        return aardKodeExtensie;
    }

    @Override
    public AardKodeExtensie getByTake(Take take) {
        return getByTake(take.getTijdperk().getCode(), take.getAard(), take.getCode(), take.getExtensie());
    }

    @Override
    public AardKodeExtensie getById(Integer id) {
        AardKodeExtensie aardKodeExtensie = aardKodeExtensieFacade.getById(id);
        checkAardKodeExtensie(aardKodeExtensie, "getById aardKodeExtensieId " + id);
        return aardKodeExtensie;
    }

    @Override
    public AardKodeExtensie getByVergoeding(Vergoeding vergoeding) {
        AardKodeExtensie aardKodeExtensie = aardKodeExtensieFacade.getByVergoeding(vergoeding);
        checkAardKodeExtensie(aardKodeExtensie,
                "getByVergoeding vergoeding met " + vergoeding.getAard() + STREEP + vergoeding.getCode() + STREEP + vergoeding.getExtensie());
        return aardKodeExtensie;
    }

    @Override
    public AardKodeExtensie getByPrestatie(NlpPrestatie prestatie) {
        AardKodeExtensie aardKodeExtensie = aardKodeExtensieFacade.getByNlpPrestatie(prestatie);
        checkAardKodeExtensie(aardKodeExtensie,
                "getByPrestatie prestatie met ake " + prestatie.getAard() + STREEP + prestatie.getCode() + STREEP + prestatie.getExtensie());
        return aardKodeExtensie;
    }

    private void checkAardKodeExtensie(AardKodeExtensie aardKodeExtensie, String message) {
        if (aardKodeExtensie == null) {
            log.debug("Probleem bij bepalen AardKodeExtensie {}", message);
            regulManager.doRegulException(null, Regulkode.VERGOEDING_NIET_GEVONDEN);
        }
    }

}
